CREATE TABLE `iceberg_s3_direct` (
  `column_int` INT,
  `column_str` STRING
) WITH (
  'connector' = 'iceberg',
  'catalog-type' = 'hadoop',          -- Replaces 'hive'
  'catalog-name' = 's3_catalog',      -- A custom name for your catalog
  'catalog-database' = 'fraud_db',    -- This will become a folder in S3
  'warehouse' = 's3://srm-iceberg/' -- The root path
);

